import java.util.*;class Player{static int W,H,n;static char[][]G;static int[][]I;static int[]S=new int[1000001];static void f(int r,int c){n++;var q=new ArrayDeque<int[]>();q.add(new int[]{r,c});I[r][c]=n;int a=0;int[]dx={1,-1,0,0},dy={0,0,1,-1};while(!q.isEmpty()){var p=q.poll();int y=p[0],x=p[1];a++;for(int i=0;i<4;i++){int ny=y+dy[i],nx=x+dx[i];if(ny>=0&&ny<H&&nx>=0&&nx<W&&I[ny][nx]<0&&G[ny][nx]=='O'){I[ny][nx]=n;q.add(new int[]{ny,nx});}}}S[n]=a;}public static void main(String[]a){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();s.nextLine();G=new char[H][];I=new int[H][W];for(int i=0;i<H;i++){G[i]=s.nextLine().toCharArray();Arrays.fill(I[i],-1);}int q=s.nextInt();while(q-->0){int x=s.nextInt(),y=s.nextInt();if(G[y][x]!='O')System.out.println(0);else{if(I[y][x]<0)f(y,x);System.out.println(S[I[y][x]]);}}}}
